package com.tradepulseai.paymentservice.controller;

import com.tradepulseai.paymentservice.model.Payment;
import com.tradepulseai.paymentservice.repository.PaymentRepository;
import io.swagger.v3.oas.annotations.Operation;
import io.swagger.v3.oas.annotations.tags.Tag;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.PathVariable;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.RestController;

import java.util.List;

@RestController
@RequestMapping("/payments")
@Tag(name = "Payments", description = "API for retrieving payment records")
public class PaymentController {

    private final PaymentRepository paymentRepository;

    public PaymentController(PaymentRepository paymentRepository) {
        this.paymentRepository = paymentRepository;
    }

    @GetMapping("/user/{userEmail}")
    @Operation(summary = "Get all payments for a user")
    public ResponseEntity<List<Payment>> getPaymentsByUserEmail(@PathVariable String userEmail) {
        return ResponseEntity.ok(paymentRepository.findByUserEmail(userEmail.toLowerCase()));
    }

    @GetMapping("/stock/{stockId}")
    @Operation(summary = "Get all payments for a stock")
    public ResponseEntity<List<Payment>> getPaymentsByStockId(@PathVariable String stockId) {
        return ResponseEntity.ok(paymentRepository.findByStockId(stockId));
    }

    @GetMapping
    @Operation(summary = "Get all payments")
    public ResponseEntity<List<Payment>> getAllPayments() {
        return ResponseEntity.ok(paymentRepository.findAll());
    }
}

package com.tradepulseai.paymentservice.grpc;

import io.grpc.stub.StreamObserver;
import net.devh.boot.grpc.server.service.GrpcService;
import order_payment.OrderPaymentRequest;
import order_payment.OrderPaymentResponse;
import order_payment.OrderPaymentServiceGrpc;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

@GrpcService
public class OrderPaymentGrpcService extends OrderPaymentServiceGrpc.OrderPaymentServiceImplBase {

    private static final Logger log = LoggerFactory.getLogger(OrderPaymentGrpcService.class);

    @Override
    public void completePayment(OrderPaymentRequest request, StreamObserver<OrderPaymentResponse> responseObserver) {
        log.info("CompletePayment request received for cartItemId={}, userEmail={}, stockId={}, qty={}",
                request.getCartItemId(), request.getUserEmail(), request.getStockId(), request.getQuantity());

        // Placeholder response until payment persistence/business rules are added.
        OrderPaymentResponse response = OrderPaymentResponse.newBuilder()
                .setAccountId("acct-" + request.getUserEmail())
                .setStatus("COMPLETED")
                .build();

        responseObserver.onNext(response);
        responseObserver.onCompleted();
    }
}

package com.tradepulseai.paymentservice.grpc;

import com.tradepulseai.paymentservice.service.PaymentProcessingService;
import io.grpc.stub.StreamObserver;
import net.devh.boot.grpc.server.service.GrpcService;
import order_payment.OrderPaymentRequest;
import order_payment.OrderPaymentResponse;
import order_payment.OrderPaymentServiceGrpc;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

@GrpcService
public class OrderPaymentGrpcService extends OrderPaymentServiceGrpc.OrderPaymentServiceImplBase {

    private static final Logger log = LoggerFactory.getLogger(OrderPaymentGrpcService.class);

    private final PaymentProcessingService paymentProcessingService;

    public OrderPaymentGrpcService(PaymentProcessingService paymentProcessingService) {
        this.paymentProcessingService = paymentProcessingService;
    }

    @Override
    public void completePayment(OrderPaymentRequest request, StreamObserver<OrderPaymentResponse> responseObserver) {
        log.info("CompletePayment request received for cartItemId={}, userEmail={}, stockId={}, qty={}",
                request.getCartItemId(), request.getUserEmail(), request.getStockId(), request.getQuantity());

        try {
            paymentProcessingService.processPayment(
                    request.getCartItemId(),
                    request.getUserEmail(),
                    request.getStockId(),
                    request.getSymbol(),
                    request.getPrice(),
                    request.getQuantity()
            );

            String accountId = paymentProcessingService.generateAccountId(request.getUserEmail());
            OrderPaymentResponse response = OrderPaymentResponse.newBuilder()
                    .setAccountId(accountId)
                    .setStatus("COMPLETED")
                    .build();

            responseObserver.onNext(response);
            responseObserver.onCompleted();
            log.info("CompletePayment response sent: accountId={}, status=COMPLETED", accountId);
        } catch (Exception e) {
            log.error("Error processing payment for cartItemId={}: {}", request.getCartItemId(), e.getMessage(), e);
            responseObserver.onError(new RuntimeException("Payment processing failed: " + e.getMessage(), e));
        }
    }
}

package com.tradepulseai.paymentservice.model;

import jakarta.persistence.Column;
import jakarta.persistence.Entity;
import jakarta.persistence.GeneratedValue;
import jakarta.persistence.GenerationType;
import jakarta.persistence.Id;
import jakarta.persistence.PrePersist;
import jakarta.persistence.Table;

import java.math.BigDecimal;
import java.time.Instant;
import java.util.UUID;

@Entity
@Table(name = "payments")
public class Payment {

    @Id
    @GeneratedValue(strategy = GenerationType.UUID)
    private UUID id;

    @Column(name = "cart_item_id", nullable = false)
    private String cartItemId;

    @Column(name = "user_email", nullable = false)
    private String userEmail;

    @Column(name = "stock_id", nullable = false)
    private String stockId;

    @Column(name = "symbol", nullable = false)
    private String symbol;

    @Column(name = "price", nullable = false, precision = 19, scale = 4)
    private BigDecimal price;

    @Column(name = "quantity", nullable = false)
    private int quantity;

    @Column(name = "total_amount", nullable = false, precision = 19, scale = 4)
    private BigDecimal totalAmount;

    @Column(name = "status", nullable = false)
    private String status;

    @Column(name = "created_at", nullable = false, updatable = false)
    private Instant createdAt;

    @PrePersist
    public void prePersist() {
        this.createdAt = Instant.now();
    }

    // Getters and setters
    public UUID getId() {
        return id;
    }

    public void setId(UUID id) {
        this.id = id;
    }

    public String getCartItemId() {
        return cartItemId;
    }

    public void setCartItemId(String cartItemId) {
        this.cartItemId = cartItemId;
    }

    public String getUserEmail() {
        return userEmail;
    }

    public void setUserEmail(String userEmail) {
        this.userEmail = userEmail;
    }

    public String getStockId() {
        return stockId;
    }

    public void setStockId(String stockId) {
        this.stockId = stockId;
    }

    public String getSymbol() {
        return symbol;
    }

    public void setSymbol(String symbol) {
        this.symbol = symbol;
    }

    public BigDecimal getPrice() {
        return price;
    }

    public void setPrice(BigDecimal price) {
        this.price = price;
    }

    public int getQuantity() {
        return quantity;
    }

    public void setQuantity(int quantity) {
        this.quantity = quantity;
    }

    public BigDecimal getTotalAmount() {
        return totalAmount;
    }

    public void setTotalAmount(BigDecimal totalAmount) {
        this.totalAmount = totalAmount;
    }

    public String getStatus() {
        return status;
    }

    public void setStatus(String status) {
        this.status = status;
    }

    public Instant getCreatedAt() {
        return createdAt;
    }

    public void setCreatedAt(Instant createdAt) {
        this.createdAt = createdAt;
    }
}

package com.tradepulseai.paymentservice.repository;

import com.tradepulseai.paymentservice.model.Payment;
import org.springframework.data.jpa.repository.JpaRepository;
import org.springframework.stereotype.Repository;

import java.util.List;
import java.util.UUID;

@Repository
public interface PaymentRepository extends JpaRepository<Payment, UUID> {
    List<Payment> findByUserEmail(String userEmail);
    List<Payment> findByStockId(String stockId);
}

package com.tradepulseai.paymentservice.service;

import com.tradepulseai.paymentservice.model.Payment;
import com.tradepulseai.paymentservice.repository.PaymentRepository;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.math.BigDecimal;
import java.util.UUID;

@Service
public class PaymentProcessingService {

    private static final Logger log = LoggerFactory.getLogger(PaymentProcessingService.class);

    private final PaymentRepository paymentRepository;

    public PaymentProcessingService(PaymentRepository paymentRepository) {
        this.paymentRepository = paymentRepository;
    }

    @Transactional
    public Payment processPayment(String cartItemId, String userEmail, String stockId, String symbol,
                                   double price, int quantity) {
        log.info("Processing payment for cartItemId={}, userEmail={}, stockId={}, qty={}, price={}",
                cartItemId, userEmail, stockId, quantity, price);

        BigDecimal priceDecimal = BigDecimal.valueOf(price);
        BigDecimal totalAmount = priceDecimal.multiply(BigDecimal.valueOf(quantity));

        Payment payment = new Payment();
        payment.setCartItemId(cartItemId);
        payment.setUserEmail(userEmail);
        payment.setStockId(stockId);
        payment.setSymbol(symbol);
        payment.setPrice(priceDecimal);
        payment.setQuantity(quantity);
        payment.setTotalAmount(totalAmount);
        payment.setStatus("COMPLETED");

        Payment savedPayment = paymentRepository.save(payment);
        log.info("Payment saved successfully with id={}, status={}, totalAmount={}",
                savedPayment.getId(), savedPayment.getStatus(), savedPayment.getTotalAmount());

        return savedPayment;
    }

    public String generateAccountId(String userEmail) {
        return "acct-" + userEmail + "-" + UUID.randomUUID().toString().substring(0, 8);
    }
}
